<script lang="ts">import {tabs,aria,type TabsState} from '../../index.js';import type {TabsProps} from '../native.js';let p:TabsProps=$props();let state:TabsState=$state({active:p.initial??0,focus:p.initial??0,activation:p.activation??'automatic'});function act(e:any){let n=tabs(state,{type:'key',key:e.key},p.items);state=n;p.onChange?.(n.active)}function pick(i:number){state=tabs(state,{type:'select',index:i},p.items);p.onChange?.(state.active)}</script>
<div class="kumo-tabs"><div role="tablist">{#each p.items as item,i}<button {...aria.tab(`${p.id}-${item.id}`,i===state.active)} disabled={item.disabled} onclick={()=>pick(i)} onkeydown={act}>{item.label}</button>{/each}</div>{#each p.items as item,i}<div {...aria.tabpanel(`${p.id}-${item.id}`)} hidden={i!==state.active}>{item.panel}</div>{/each}</div>
